BEGIN TRANSACTION;
CREATE TABLE brands (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	category VARCHAR(100) NOT NULL, 
	instagram VARCHAR(255), 
	facebook VARCHAR(255), 
	xiaohongshu VARCHAR(255), 
	x_twitter VARCHAR(255), 
	reddit VARCHAR(255), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
