INSERT OR IGNORE INTO content_items VALUES(602,3,'instagram','3849039059281752562','eastpak','https://www.instagram.com/p/DVqiKGfF7Hy/',unistr('Walter Van Beirendonck x Eastpak \u000a\u000aFirst unveiled during Paris Fashion Week, the Walter Pak’r is now officially available in three bold monochrome shades. A fusion of Walter’s fearless imagination and Eastpak’s iconic design. \u000a\u000aShop the Walter Pak’r on http://eastpak.com/'),'video','2026-03-09 13:00:00.000000',-1,47,0,0,10407,NULL,140.0,NULL,1.0,2.294548413344182248,'product_showcase',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
