INSERT OR IGNORE INTO content_items VALUES(604,3,'instagram','3841912039262751238','eastpak','https://www.instagram.com/p/DVRNqT2jYoG/',unistr('Ideas don’t arrive fully formed. They travel.\u000a\u000aSometimes packed in a luggage with everything still in progress.\u000a\u000a📸@simone.paccini'),'carousel','2026-02-27 17:00:00.000000',-1,6,0,0,0,NULL,17.0,NULL,1.0,0.2929210740439381345,'travel_adventure',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(605,3,'instagram','3848223495960774945','eastpak','https://www.instagram.com/p/DVnouF9Dckh/',unistr('“I don’t work in fashion. I work in music, using fashion.”\u000a\u000aStylist @francesco_mautone moves with his Eastpak bag where ideas are still unfinished.\u000a\u000a📸@simone.paccini'),'image','2026-03-08 10:00:00.000000',-1,4,0,0,0,NULL,11.0,NULL,1.0,0.1952807160292921173,'urban_lifestyle',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(606,3,'instagram','3840027490500340373','eastpak','https://www.instagram.com/p/DVKhKhDAeqV/',unistr('…\u000aJANSPORT × EASTPAK × BEAMS\u000a『Hybrid Pack』\u000a3.3(Tue.) Release\u000a.\u000aBEAMS創業50周年を記念し、アメリカを代表する老舗バックブランド〈JANSPORT〉と〈EASTPAK〉による、前代未聞のスペシャルコラボレーションが実現。両ブランドのアイコニックなバックパックを融合させた特別モデル『Hybrid Pack』をリリース。\u000a\u000a本作は、左半分に〈JANSPORT〉の名作『Right Pack』、右半分に〈EASTPAK〉の定番『Padded Pak’r』を採用。\u000aそれぞれのシルエットや素材使い、カラーリングはもちろん、フロントポケットの形状、スウェードレザーボトム、背面パネルのポケット仕様に至るまで、両モデルの個性を忠実に再現しています。\u000a\u000a内装には、キークリップやPCスリーブなどの実用的なディテールもそのまま継承。デザインのインパクトと日常使いの機能性を両立させました。\u000a\u000a長きにわたり世界中で愛されてきた2つの名作へのリスペクトを込めて。\u000a50年の歩みを重ねてきた〈BEAMS〉だからこそ実現した、特別な別注モデルです。\u000a\u000a〈BEAMS〉では、グリーン × ネイビー、グレー × グレー、ブラック × ブラック\u000aの3色、〈BEAMS BOY〉ではネイビー × レッドを展開。各レーベル取り扱い店舗(一部店舗を除く)、ビームス公式オンラインショップにて3月3日（火）より発売です。\u000a.\u000aTo celebrate the 50th anniversary of BEAMS, an unprecedented special collaboration has been realized between two iconic American heritage bag brands, JANSPORT and EASTPAK. The project introduces the exclusive “Hybrid Pack,” a one-of-a-kind model that fuses the most recognizable backpacks from both brands into a single design.\u000a\u000aThis unique piece features JANSPORT’s masterpiece “Right Pack” on the left half and EASTPAK’s classic “Padded Pak’r” on the right. From silhouette, material selection, and color schemes to the front pocket shapes, suede leather bottom, and back panel pocket specifications, each side faithfully recreates the distinct identity of its original model.\u000a\u000aThe interior retains practical details such as a key clip and PC sleeve, seamlessly combining striking visual impact with everyday functionality.\u000a\u000aCreated with deep respect for two timeless classics loved around the world, this exclusive model could only be realized by BEAMS as it marks 50 years of its journey.\u000a\u000aBEAMS will release three colorways: Green × Navy, Gray × Gray, and Black × Black. BEAMS BOY will offer Navy × Red. Available from March 3 (Tuesday) at BEAMS label stores (excluding select locations) and the official BEAMS online shop.\u000a.\u000a@jansport\u000a@jansportjp\u000a@eastpak\u000a@beams_official\u000a@beams_mens_casual\u000a@beams_boy_official\u000a#jansport\u000a#eastpak\u000a#beams'),'video','2026-02-25 03:06:58.000000',649,4,0,0,11139,NULL,661.0,NULL,1.0,10.77298616761594907,'product_showcase',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(607,3,'instagram','3846864940184362449','eastpak','https://www.instagram.com/p/DViz0gSl93R/',unistr('The look is only the surface.\u000aThe work happens before.\u000a\u000aA portrait of stylist @francesco_mautone, between fittings and thoughts, during the busiest week of the year.\u000a📸@simone.paccini'),'video','2026-03-06 13:00:00.000000',-1,10,0,0,1853,NULL,29.0,NULL,1.0,0.4882017900732302795,'urban_lifestyle',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(608,3,'instagram','3840402343670407432','eastpak','https://www.instagram.com/p/DVL2ZWRDWEI/',unistr('The journey starts before the spotlight.\u000a\u000aWe followed stylist @francesco_mautone at work in Italy, shaping each outfit in transit. Resist’r and Travelpack carried the wardrobe, the tools, the process.\u000a\u000aThe show begins on the road.\u000a📸 @simone.paccini'),'carousel','2026-02-25 15:00:00.000000',-1,12,0,0,0,NULL,35.0,NULL,1.0,0.5858421480878762689,'travel_adventure',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(609,3,'instagram','3844025955409320342','eastpak','https://www.instagram.com/p/DVYuT1rjdmW/',unistr('No final look without the in-between. \u000aFittings mean conversations, adjustments, last-minute changes. \u000aThe bag filled with the camera, pins, and clips inside.\u000aThat’s where the work happens.\u000a\u000a📸@simone.paccini'),'carousel','2026-03-03 15:00:00.000000',-1,5,0,0,0,NULL,14.0,NULL,1.0,0.2441008950366151397,'urban_lifestyle',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(610,3,'instagram','3851938006655958120','eastpak','https://www.instagram.com/p/DV01TVnjfxo/',unistr('The Walter Pak’r sold out in just 24 hours on our website, but more is yet to come. ​\u000a​\u000aIt’s making its comeback with the addition of new styles to the collection. Available on our website and selected retailers this September 2026!​\u000a​\u000aMark your calendar!'),'carousel','2026-03-11 18:20:00.000000',-1,34,0,0,0,NULL,101.0,NULL,1.0,1.65988608624898304,'product_showcase',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
