INSERT OR IGNORE INTO content_items VALUES(613,3,'instagram','3822204777933859971','eastpak','https://www.instagram.com/p/DULMv6fjGyD/',unistr('My Eastpak carried my whole world. \u000a\u000aGrowing up queer in a tough environment meant I had to hide parts of myself. But that bag became one of the only places where I could express who I really was, scribbling my thoughts and dreams all over it, and having my Granny sew patches on.\u000a\u000aYears later, we are so proud to recreate this bag with @eastpak for our AW26 show.'),'carousel','2026-01-31 12:25:37.000000',-1,10,0,0,0,NULL,29.0,NULL,1.0,0.4882017900732302795,NULL,0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
