INSERT OR IGNORE INTO content_items VALUES(620,3,'instagram','3820229069682593700','eastpak','https://www.instagram.com/p/DUELhkzDU-k/',unistr('BTS of the show. \u000a\u000aA look at the color, movement, and raw energy happening backstage as our worlds came together moments before hitting the runway.\u000a\u000aWalter Pak’r available on March 9th, 2026 on Eastpak.com and official retailers.'),'carousel','2026-01-28 19:00:00.000000',-1,8,0,0,0,NULL,23.0,NULL,1.0,0.3905614320585842347,NULL,0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
