INSERT OR IGNORE INTO content_items VALUES(626,3,'instagram','3819323303727586740','eastpak','https://www.instagram.com/p/DUA9k8hDd20/',unistr('The collaboration you could feel.​\u000a​\u000aWalter’s bold visual universe blending with Eastpak’s design DNA in a way that felt fresh, energetic, and unmistakably us. The atmosphere captured the spirit of our long-standing partnership: creative, fearless, and full of unexpected moments.'),'carousel','2026-01-27 13:00:00.000000',-1,14,0,0,0,NULL,41.0,NULL,1.0,0.6834825061025223691,'product_showcase',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
