INSERT OR IGNORE INTO content_items VALUES(632,3,'instagram','3850548973438606602','eastpak','https://www.instagram.com/p/DVv5ePoDZ0K/',unistr('A collaboration years in the making. \u000a\u000aThe Walter Pak’r returns in three bold monochrome shades: Military Green, blue and Orange. \u000a\u000aA reinterpretation shaped by a long‑standing creative partnership with Walter Van Beirendonck, from the first monster silhouette in 2004 to today’s new evolution. \u000a\u000aShop the Walter Pak’r on http://eastpak.com/'),'carousel','2026-03-10 15:00:00.000000',-1,18,0,0,0,NULL,53.0,NULL,1.0,0.8787632221318144588,'campaign_seasonal',0,NULL,'2026-03-19 09:22:16','2026-03-19 09:34:18');
