INSERT OR IGNORE INTO content_items VALUES(672,7,'instagram','3836686517792413962','bellroy','https://www.instagram.com/p/DU-pg9vjBkK/',unistr('It''s a sling! It''s a duffel! No (Yes) – it''s the Cinch Carryall 🤩 We''ve combined the most loved parts of a sling and duffel bag to create the Cinch Carryall. Pack a lot in for your day-to-day exploits, or weekend away. It''s up to you, and it''s all fun.\u000a\u000aShop it via our link in bio 🔗'),'carousel','2026-02-20 11:58:34.000000',570,23,0,0,0,NULL,639.0,NULL,1.0,16.35903003981179893,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
