INSERT OR IGNORE INTO content_items VALUES(674,7,'instagram','3824367205123647014','bellroy','https://www.instagram.com/p/DUS4bXwDGYm/',unistr('🚨Attention: Cinch lovers🚨\u000aFirst, we mini-fied the Cinch Backpack (hello, Minipack) and Messenger (AKA Mini Messenger). And you loved that. So we''ve made Cinch even MORE mini, and ✨attachable✨\u000aFor your tiny carry needs: the Cinch Pouch and Cinch Pocket.\u000a\u000aShop the Attachables range at our link in bio.'),'carousel','2026-02-03 12:02:05.000000',271,10,0,0,0,NULL,301.0,NULL,1.0,4.12595005428881656,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(675,7,'instagram','3794527413464787261','bellroy','https://www.instagram.com/p/DSo3pQKDOk9/','Knotty or nice? 🪢 Know someone on the knotty list this year? Tag them below (or maybe just gift them a Tech Kit).','video','2025-12-24 08:00:25.000000',232,7,0,0,8468,NULL,253.0,NULL,1.0,2.388707926167209727,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(676,7,'instagram','3805652269019575649','bellroy','https://www.instagram.com/p/DTQZJNRkjVh/','Our limited-edition Year of the Horse capsule is galloping your way next week – as well as a special journey behind the design with Bellroy designer, Rowan. Sign up via link in bio to be first to know when it drops 🔗','video','2026-01-08 16:19:17.000000',462,16,0,0,10700,NULL,510.0,NULL,1.0,11.69019182048497995,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(677,7,'instagram','3799603501271013228','bellroy','https://www.instagram.com/p/DS650DUltds/','A few highlights from 2025. Thanks for being part of the journey ♥️ and Happy New Year!','carousel','2025-12-31 08:01:16.000000',356,11,0,0,0,NULL,389.0,NULL,1.0,7.310893955845096492,'travel_adventure',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(678,7,'instagram','3793923539393668280','bellroy','https://www.instagram.com/p/DSmuVumjWS4/','Secret portal to an infinite drinks dimension? Or just 10L of waterproof cooler bag space for all that “bring something to drink” holiday season socializing. Thank you, Lite Cooler Caddy.','video','2025-12-23 12:00:14.000000',237,13,0,0,12209,NULL,276.0,NULL,1.0,3.221136445892146316,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(679,7,'instagram','3798272096833860345','bellroy','https://www.instagram.com/p/DS2LFkUD3L5/','Lucky enough to unbox a Transit Carry-On like @georgeemad16 recently? 🎁 Whether it’s fresh out of the box or already rolling, tell us what you think below👇','video','2025-12-29 12:00:26.000000',728,40,0,0,14786,NULL,848.0,NULL,1.0,23.92327180600796055,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(680,7,'instagram','3795252254845225714','bellroy','https://www.instagram.com/p/DSrcdFTDMry/',unistr('From all of us at Bellroy 💝\u000aWe hope your holiday season’s packed full of cheer.'),'video','2025-12-25 08:00:23.000000',260,7,0,0,3820,NULL,281.0,NULL,1.0,3.402099167571480454,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(681,7,'instagram','3811318127079407616','bellroy','https://www.instagram.com/p/DTkhaSyk0AA/','Have you seen our new Year of the Horse Collection yet? Join our Designer, Rowan, as they share the thinking behind the New Year Horse Charm (and some smooth Tai Chi moves) – available for free with the limited edition Cinch Mini Messenger or Cinch Backpack. Get yours via link in bio 🔗','video','2026-01-16 12:00:36.000000',227,16,0,0,9714,NULL,275.0,NULL,1.0,3.184943901556279488,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(682,7,'instagram','3814204457022693032','bellroy','https://www.instagram.com/p/DTuxr7BjJ6o/',unistr('Our original slim wallets – the Hide & Seek, Note Sleeve and Slim Sleeve, have just launched in INNOVERA™ Black. INNOVERA™ is a bio-based leather alternative that has that luxe leather feel, with an unexpected level of wear resistance.\u000a\u000aShop the INNOVERA™ Collection at our link in bio.'),'carousel','2026-01-20 11:30:42.000000',442,14,0,0,0,NULL,484.0,NULL,1.0,10.74918566775244421,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(683,7,'instagram','3798999450367709590','bellroy','https://www.instagram.com/p/DS4wd9FElGW/','What do you reaaaaaaaalllly want to see from us in 2026? 👀 Let us know what’s on your new gear wish list and we might just make it happen ✨','image','2025-12-30 12:00:56.000000',308,230,0,0,0,NULL,998.0,NULL,1.0,29.35215345638798467,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(684,7,'instagram','3812045733504564081','bellroy','https://www.instagram.com/p/DTnG2XFFTtx/',unistr('For a limited time, nab a free bag-charm duo with your purchase of the Year of the Horse Cinch Mini Messenger or Backpack 💥\u000aThese horse and owl collectables are unmissable – and quickly galloping off the shelves. Get in quick – the race is on!\u000a\u000aShop the Year of the Horse Collection at our link in bio.'),'carousel','2026-01-17 12:01:38.000000',819,15,0,0,0,NULL,864.0,NULL,1.0,24.50235251538182979,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(685,7,'instagram','3809886075007885967','bellroy','https://www.instagram.com/p/DTfbzMXjWKP/',unistr('Our limited Year of the Horse Collection is here 🎉🐴 We’ve given our fave Cinch styles (and 2 newbies) a makeover to celebrate the new year. Plus, custom bag charms come included with the two bag styles.\u000a\u000aShop the Collection at our link in bio.'),'carousel','2026-01-14 12:30:51.000000',582,35,0,0,0,NULL,687.0,NULL,1.0,18.09627216793340665,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(686,7,'instagram','3806346271880321826','bellroy','https://www.instagram.com/p/DTS28Rzjxsi/',unistr('We love seeing you carry your Bellroys all over the globe 🌏 ✈️ \u000a\u000aWhere are you headed next?'),'carousel','2026-01-09 15:17:54.000000',339,16,0,0,0,NULL,387.0,NULL,1.0,7.238508867173362837,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(687,7,'instagram','3774900548781565312','bellroy','https://www.instagram.com/p/DRjJAyAjWWA/',unistr('Smooth travel''s all in the details. And we''ve got those in the bag 👌\u000a\u000aCheck out our Travel Collection at the link in bio.'),'carousel','2025-11-27 06:01:05.000000',840,23,0,0,0,NULL,909.0,NULL,1.0,26.13101701049583881,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(688,7,'instagram','3779822953824193422','bellroy','https://www.instagram.com/p/DR0oPM8jwuO/','Coming soon to a Bellroy collection near you... But first, it needs a name. What would you call this color combo? Drop your suggestions in the comments 👀','image','2025-12-04 01:00:38.000000',272,129,0,0,0,NULL,659.0,NULL,1.0,17.08288092652913548,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(689,7,'instagram','3773657623229831704','bellroy','https://www.instagram.com/p/DReuZ1YjxoY/','As well as replaceable parts, quiet wheels and expert organization, the Transit Carry-On’s also pretty tough 💪 Listen to our Head of Product Design describe what we did to make sure this bag could handle the hustle, bustle and bumps of holiday season. Then get yours via link in bio 🔗','video','2025-11-25 12:55:05.000000',516,18,0,0,12155,NULL,570.0,NULL,1.0,13.8617444806369896,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(690,7,'instagram','3785950944778623058','bellroy','https://www.instagram.com/p/DSKZlNQlZhS/','Looking for a gift they’ll carry every day for years to come? Check out our wallet range, made to get better with age, day 1 to day 1000 and beyond. Shop via link in bio 🔗','video','2025-12-12 12:00:10.000000',450,27,0,0,10659,NULL,531.0,NULL,1.0,12.45023525153818334,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(691,7,'instagram','3780155618603362327','bellroy','https://www.instagram.com/p/DR1z4HKjOgX/',unistr('Catch it while you can! 🔥 Right now, get a FREE Lite Belt Bag with all eligible purchases. Choose from five colors, including limited-edition Firefly. \u000a\u000aStart shopping via link in bio 🔗'),'carousel','2025-12-04 12:01:47.000000',859,46,0,0,0,NULL,997.0,NULL,1.0,29.31596091205211963,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(692,7,'instagram','3769223738017617689','bellroy','https://www.instagram.com/p/DRO-QT_gpcZ/',unistr('We''re so fond of our wallets on Day 1000, we trademarked the idea... Check out these beauties, with that unique patina and some of the softest leather around.\u000a\u000aGet your day 1 at our link in bio.'),'carousel','2025-11-19 10:01:55.000000',527,18,0,0,0,NULL,581.0,NULL,1.0,14.25986246833152471,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(693,7,'instagram','3791098744335941688','bellroy','https://www.instagram.com/p/DScsDjMksA4/','In-house design team tests, tinkers and tests again to build gear with thoughtful details that’ll make your everyday smoother – every pocket, zip, snap and satisfying whooshk. What’s your fave feature?','carousel','2025-12-19 14:23:29.000000',348,16,0,0,0,NULL,396.0,NULL,1.0,7.564241766196164285,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(694,7,'instagram','3768429392876957722','bellroy','https://www.instagram.com/p/DRMJpEbknAa/',unistr('From dog walk to downtown, our slings go where you do! 🙌  Thanks for tagging us.\u000a.\u000aAnd right now, you can get 25% off any sling when you buy a backpack. Find your perfect pairing via link in bio 🔗'),'carousel','2025-11-18 07:43:32.000000',283,7,0,0,0,NULL,304.0,NULL,1.0,4.234527687296417043,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(695,7,'instagram','3788853443277717657','bellroy','https://www.instagram.com/p/DSUtiHolYCZ/',unistr('Got some Bellroy gear on your holiday shopping list? There''s still time to get what you need...\u000a1️⃣ Online shopper? Be quick! And check our regional shipping cut-off dates via link in bio.\u000a2️⃣ Prefer that in-store experience? We have stockists all over the globe – find your nearest via link in bio. (Then call ahead to make sure they stock the product you want!)'),'carousel','2025-12-16 12:02:42.000000',1516,51,0,0,0,NULL,1669.0,NULL,1.0,53.63735070575461351,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(696,7,'instagram','3768165375071680707','bellroy','https://www.instagram.com/p/DRLNnGsEvjD/',unistr('Get 25% off a sling when you buy a backpack. The ultimate collab, for less.\u000a\u000aShop the eligible combos at our link in bio 🔗'),'carousel','2025-11-17 22:58:59.000000',416,15,0,0,0,NULL,461.0,NULL,1.0,9.91675714802750719,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(697,7,'instagram','3770559311475707233','bellroy','https://www.instagram.com/p/DRTt7dtDQ1h/','Check out our recent collab with Simple Beautiful Things in Sydney – a space that shares our love for considered designs that elevate everyday living. And big thanks to everyone who stopped by.','carousel','2025-11-21 06:15:37.000000',448,14,0,0,0,NULL,490.0,NULL,1.0,10.9663409337676434,'product_showcase',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(698,7,'instagram','3783776639537579393','bellroy','https://www.instagram.com/p/DSCrM5tDwWB/','Anything for the shot. Check out some BTS footage for our limited-edition ‘Firefly’ Lite Belt Bag, currently free with all eligible purchases. Catch it while you can! Shop now via the link in bio 🔗','video','2025-12-09 12:00:07.000000',218,5,0,0,5326,NULL,233.0,NULL,1.0,1.6648570394498734,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(699,7,'instagram','3791752066616808861','bellroy','https://www.instagram.com/p/DSfAmo_DFWd/','Check out some of the festive fun we had at @davidjonesstore’ Christmas Shopping Festival at Bourke Street, Melbourne🎄Thanks to everyone who stopped by our recent in-store activation. From great gear to Spin the Wheel giveaways, it was great being part of such a memorable shopping experience. Happy Holidays 🎁','carousel','2025-12-20 12:01:48.000000',268,0,0,0,0,NULL,268.0,NULL,1.0,2.931596091205211696,'urban_lifestyle',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(700,7,'instagram','3784501371613536104','bellroy','https://www.instagram.com/p/DSFP_JDAN9o/',unistr('The Lite Belt Bag is surprisingly spacious. And you can get one for ✨ free ✨ right now with eligible purchases – including the limited-edition ''Firefly''. 💥\u000a\u000aClaim yours! Start shopping via the link in bio.'),'video','2025-12-10 12:00:10.000000',618,28,0,0,6719,NULL,702.0,NULL,1.0,18.63916033297140729,'campaign_seasonal',0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
INSERT OR IGNORE INTO content_items VALUES(701,7,'instagram','3820015445794367523','bellroy','https://www.instagram.com/p/DUDa88DFCgj/','Meet the Attachables 😍 Small accessories with big upgrade energy. Add one, two, or a few, to give your carry setup extra personality and organization ✨ Get attached via link in bio 🔗','video','2026-01-28 12:00:25.000000',921,22,0,0,13911,NULL,987.0,NULL,1.0,28.95403546869345135,NULL,0,NULL,'2026-03-19 09:23:44','2026-03-19 09:34:18');
