BEGIN TRANSACTION;
CREATE TABLE content_media (
	id INTEGER NOT NULL, 
	content_id INTEGER NOT NULL, 
	media_type VARCHAR(50) NOT NULL, 
	original_url TEXT, 
	local_path TEXT, 
	width INTEGER, 
	height INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(content_id) REFERENCES content_items (id)
);
