BEGIN TRANSACTION;
CREATE TABLE content_briefs (
	id INTEGER NOT NULL, 
	source_content_id INTEGER NOT NULL, 
	style_analysis JSON, 
	headline VARCHAR(500), 
	caption_draft TEXT, 
	suggested_post_type VARCHAR(50), 
	suggested_theme VARCHAR(100), 
	slide_count INTEGER, 
	visual_direction TEXT, 
	cta_suggestion TEXT, 
	hashtag_suggestions TEXT, 
	status VARCHAR(50) NOT NULL, 
	editor_notes TEXT, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	suggested_product VARCHAR(100), 
	deep_analysis JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(source_content_id) REFERENCES content_items (id)
);
INSERT OR IGNORE INTO content_briefs VALUES(1,695,'{"tone": "Helpful, urgent, and professional", "caption_structure": "Short, informational, and categorized with numbered points for readability.", "cta_pattern": "Direct call to action directing users to the link in bio for both online and in-store shopping options.", "emoji_usage": "Functional and minimal, using numbers to organize instructions.", "post_format": "Retail display showcase with informative holiday shopping guidance.", "hook_style": "Problem-solution oriented, addressing holiday gifting deadlines.", "hashtag_strategy": "None visible, prioritizing clean, informative messaging.", "image_style": "High-quality retail interior photography, structured and organized shelf display.", "background_description": "A well-lit, branded Bellroy retail display unit with matte olive green curved shelving and recessed LED accent lighting.", "color_palette": "Deep olive green, light grey, burnt orange, and natural wood tones.", "people_and_models": "None; the focus is entirely on product organization.", "product_placement": "Hero placement; products are artfully arranged by size, color, and type on custom shelving to demonstrate a curated, premium shopping experience.", "overall_vibe": "Clean, organized, and inviting, emphasizing a premium retail holiday shopping experience."}','Elevate your carry this season with the Astir Large.',unistr('Looking to gift the ultimate urban companion? The Astir Large from our Black Series is officially ready for the holiday rush. Here is how to secure yours in time:\u000a\u000a1️⃣ Ordering online? Place your orders early to beat the holiday transit window. Check our regional shipping cut-off dates via the link in our bio.\u000a\u000a2️⃣ Prefer to see it in person? Visit our flagship stores or our local stockists. Find your nearest location through our store locator in bio. (We recommend calling ahead to confirm availability of the Astir Large!).'),'carousel','product_showcase',8,'High-quality retail interior photography, structured and organized shelf display.','Tap the link in our bio to find your local store or shop the Black Series online.','DoughnutOfficial, PackYourDream, AstirLarge, HolidayGifting, UrbanCommuter, BlackSeries','draft',NULL,'2026-03-19 15:12:47','2026-03-19 15:12:47','Astir Large','{"tone": "Helpful, urgent, and professional", "caption_structure": "Short, informational, and categorized with numbered points for readability.", "cta_pattern": "Direct call to action directing users to the link in bio for both online and in-store shopping options.", "emoji_usage": "Functional and minimal, using numbers to organize instructions.", "post_format": "Retail display showcase with informative holiday shopping guidance.", "hook_style": "Problem-solution oriented, addressing holiday gifting deadlines.", "hashtag_strategy": "None visible, prioritizing clean, informative messaging.", "image_style": "High-quality retail interior photography, structured and organized shelf display.", "background_description": "A well-lit, branded Bellroy retail display unit with matte olive green curved shelving and recessed LED accent lighting.", "color_palette": "Deep olive green, light grey, burnt orange, and natural wood tones.", "people_and_models": "None; the focus is entirely on product organization.", "product_placement": "Hero placement; products are artfully arranged by size, color, and type on custom shelving to demonstrate a curated, premium shopping experience.", "overall_vibe": "Clean, organized, and inviting, emphasizing a premium retail holiday shopping experience."}');
INSERT OR IGNORE INTO content_briefs VALUES(2,644,'{"tone": "Mysterious, urban, and high-energy.", "caption_structure": "Minimalist and cryptic, utilizing a date-stamp format followed by high-emphasis emojis.", "cta_pattern": "None; the post relies on pure intrigue and brand presence rather than a direct sales prompt.", "emoji_usage": "Repetitive, attention-grabbing icons used to create a sense of urgency or announcement.", "post_format": "Editorial-style photography focusing on lifestyle movement and product durability.", "hook_style": "Temporal hook using a specific date to imply an upcoming event, launch, or campaign phase.", "hashtag_strategy": "None; prioritizing brand exclusivity and stylistic minimalism.", "image_style": "High-contrast, stylized, desaturated blue-tinted photography with an editorial, motion-blurred aesthetic.", "background_description": "Clean, overexposed white background creating a stark, high-key silhouette effect.", "color_palette": "Monochromatic blue tint on a stark white backdrop.", "people_and_models": "Person from the back in motion, carrying a backpack and suitcase with a skateboard, representing the active, mobile traveler.", "product_placement": "In-use lifestyle integration, where the backpack and luggage are central to the composition and define the silhouette of the subject.", "overall_vibe": "An edgy, fast-paced atmosphere that positions the brand as the essential companion for the modern, on-the-go lifestyle."}','Tuesday, October 24th.','Shift the gear. Move without hesitation. ⚡⚡⚡','carousel',NULL,9,'High-contrast, stylized, desaturated blue-tinted photography with an editorial, motion-blurred aesthetic.','','','draft',NULL,'2026-03-19 16:07:39','2026-03-19 16:07:39','Navigator Duffelpack','{"tone": "Mysterious, urban, and high-energy.", "caption_structure": "Minimalist and cryptic, utilizing a date-stamp format followed by high-emphasis emojis.", "cta_pattern": "None; the post relies on pure intrigue and brand presence rather than a direct sales prompt.", "emoji_usage": "Repetitive, attention-grabbing icons used to create a sense of urgency or announcement.", "post_format": "Editorial-style photography focusing on lifestyle movement and product durability.", "hook_style": "Temporal hook using a specific date to imply an upcoming event, launch, or campaign phase.", "hashtag_strategy": "None; prioritizing brand exclusivity and stylistic minimalism.", "image_style": "High-contrast, stylized, desaturated blue-tinted photography with an editorial, motion-blurred aesthetic.", "background_description": "Clean, overexposed white background creating a stark, high-key silhouette effect.", "color_palette": "Monochromatic blue tint on a stark white backdrop.", "people_and_models": "Person from the back in motion, carrying a backpack and suitcase with a skateboard, representing the active, mobile traveler.", "product_placement": "In-use lifestyle integration, where the backpack and luggage are central to the composition and define the silhouette of the subject.", "overall_vibe": "An edgy, fast-paced atmosphere that positions the brand as the essential companion for the modern, on-the-go lifestyle."}');
INSERT OR IGNORE INTO content_briefs VALUES(3,656,'{"tone": "Exciting, professional, and lifestyle-oriented", "caption_structure": "Short, punchy introductory hook followed by value proposition highlights and a clear call to action.", "cta_pattern": "Direct instructions to visit the link in bio for shopping.", "emoji_usage": "Light and functional, using emotive faces and relevant icons to punctuate the brand message.", "post_format": "High-quality, studio-lit product photography utilizing a conceptual background overlay.", "hook_style": "Urgency-driven announcement confirming product availability.", "hashtag_strategy": "Minimalist or hidden approach, focusing on brand equity over discoverability.", "image_style": "Clean, minimalist studio aesthetic with a graphic element (the airplane window shape) to provide visual context.", "background_description": "A clean, off-white studio background with a centered, rounded-rectangular window shape showing a realistic blue sky with clouds.", "color_palette": "Neutral and sophisticated; black, off-white, and light blue sky tones.", "people_and_models": "None; focus is exclusively on the product design and utility.", "product_placement": "Hero placement in the center, positioning the items as high-quality, essential travel gear.", "overall_vibe": "A polished, aspirational, and premium travel brand presentation that emphasizes durability and style."}','Elevate your journey, refined.','The wait is finally over. Meet the Navigator Duffelpack—the ultimate fusion of professional aesthetics and rugged utility. Engineered for the modern urban traveler, this hybrid carry redefines versatility without compromising on style. From high-stakes meetings to weekend escapes, carry your essentials with unparalleled ease. Elevate your travel game today. Shop the DN Black Series via the link in our bio.','carousel','travel_adventure',11,'Clean, minimalist studio aesthetic with a graphic element (the airplane window shape) to provide visual context.','Shop the DN Black Series via the link in our bio.','#DoughnutOfficial, #DoughnutBlackSeries, #NavigatorDuffelpack, #TravelInStyle, #UrbanCommuter, #PremiumTravelGear','draft',NULL,'2026-03-19 16:13:10','2026-03-19 16:13:10','Navigator Duffelpack','{"tone": "Exciting, professional, and lifestyle-oriented", "caption_structure": "Short, punchy introductory hook followed by value proposition highlights and a clear call to action.", "cta_pattern": "Direct instructions to visit the link in bio for shopping.", "emoji_usage": "Light and functional, using emotive faces and relevant icons to punctuate the brand message.", "post_format": "High-quality, studio-lit product photography utilizing a conceptual background overlay.", "hook_style": "Urgency-driven announcement confirming product availability.", "hashtag_strategy": "Minimalist or hidden approach, focusing on brand equity over discoverability.", "image_style": "Clean, minimalist studio aesthetic with a graphic element (the airplane window shape) to provide visual context.", "background_description": "A clean, off-white studio background with a centered, rounded-rectangular window shape showing a realistic blue sky with clouds.", "color_palette": "Neutral and sophisticated; black, off-white, and light blue sky tones.", "people_and_models": "None; focus is exclusively on the product design and utility.", "product_placement": "Hero placement in the center, positioning the items as high-quality, essential travel gear.", "overall_vibe": "A polished, aspirational, and premium travel brand presentation that emphasizes durability and style."}');
INSERT OR IGNORE INTO content_briefs VALUES(4,644,'{"tone": "Mysterious, urban, and understated.", "caption_structure": "Minimalist and cryptic, utilizing a specific date marker followed by emphatic emojis to build curiosity.", "cta_pattern": "Non-existent; the post relies on pure intrigue rather than a direct request for action.", "emoji_usage": "Repetitive, attention-grabbing, and used as a stylistic punctuation mark rather than descriptive context.", "post_format": "Teaser post, likely part of a countdown or campaign launch.", "hook_style": "Date-based suspense, providing a specific temporal anchor to generate anticipation.", "hashtag_strategy": "None visible, focusing on brand enigma over reach.", "image_style": "High-contrast, stylized monochrome photography with a strong blue tint, evoking a kinetic, urban, and high-fashion streetwear aesthetic.", "background_description": "Blown-out, high-key white background that isolates the subject and emphasizes the silhouette.", "color_palette": "Monochromatic blue-tinted shadows against a stark white backdrop.", "people_and_models": "A person viewed from behind, loaded with travel gear, suggesting transit, adventure, and movement.", "product_placement": "Hero product focus; the Eastpak backpack and the gear-heavy styling are center-frame, presented as a lifestyle necessity for the modern traveler.", "overall_vibe": "Energetic and enigmatic, capturing the spirit of perpetual motion and urban readiness."}','Tuesday, October 24th.','Tuesday, October 24th. ⬛⬛⬛','carousel',NULL,9,'High-contrast, stylized monochrome photography with a strong blue tint, evoking a kinetic, urban, and high-fashion streetwear aesthetic.','','','draft',NULL,'2026-03-19 17:06:00','2026-03-19 17:06:00','Navigator Duffelpack','{"tone": "Mysterious, urban, and understated.", "caption_structure": "Minimalist and cryptic, utilizing a specific date marker followed by emphatic emojis to build curiosity.", "cta_pattern": "Non-existent; the post relies on pure intrigue rather than a direct request for action.", "emoji_usage": "Repetitive, attention-grabbing, and used as a stylistic punctuation mark rather than descriptive context.", "post_format": "Teaser post, likely part of a countdown or campaign launch.", "hook_style": "Date-based suspense, providing a specific temporal anchor to generate anticipation.", "hashtag_strategy": "None visible, focusing on brand enigma over reach.", "image_style": "High-contrast, stylized monochrome photography with a strong blue tint, evoking a kinetic, urban, and high-fashion streetwear aesthetic.", "background_description": "Blown-out, high-key white background that isolates the subject and emphasizes the silhouette.", "color_palette": "Monochromatic blue-tinted shadows against a stark white backdrop.", "people_and_models": "A person viewed from behind, loaded with travel gear, suggesting transit, adventure, and movement.", "product_placement": "Hero product focus; the Eastpak backpack and the gear-heavy styling are center-frame, presented as a lifestyle necessity for the modern traveler.", "overall_vibe": "Energetic and enigmatic, capturing the spirit of perpetual motion and urban readiness."}');
INSERT OR IGNORE INTO content_briefs VALUES(5,656,'{"tone": "Exciting, polished, and professional", "caption_structure": "Short, punchy sentence to build excitement, followed by value proposition, and a clear call-to-action.", "cta_pattern": "Direct instructions to shop via link in bio.", "emoji_usage": "Minimal and strategic, using symbols to emphasize emotion and direction.", "post_format": "Product-focused carousel featuring hero lifestyle/studio hybrid imagery.", "hook_style": "Direct announcement hook to capture immediate interest.", "hashtag_strategy": "Minimalist, focused on brand identity and core product category.", "image_style": "Clean studio product photography with creative digital composite background.", "background_description": "Gradient light grey background featuring a rounded-rectangular window shape showing a clear blue sky and fluffy white clouds to evoke travel themes.", "color_palette": "Monochromatic neutrals (black and beige) contrasted with bright sky blue and white.", "people_and_models": "None, focus is entirely on the product.", "product_placement": "Hero placement with the two luggage pieces side-by-side in the center, clearly displaying branding.", "overall_vibe": "Sophisticated, aspirational, and clean, highlighting a premium travel experience."}','Elevate your journey.','The wait is over! Meticulously crafted for the modern nomad, the Navigator Duffelpack combines professional-grade organization with a sleek, minimalist aesthetic. Whether you’re navigating the urban sprawl or boarding your next flight, experience seamless travel refined for your daily commute. Explore the DN Black Series via the link in our bio. ✈️','carousel','travel_adventure',11,'Clean studio product photography with creative digital composite background.','Shop the Navigator Duffelpack via the link in our bio.','#DoughnutOfficial, #DNBlackSeries, #NavigatorDuffelpack, #TravelInStyle, #UrbanCommuter','draft',NULL,'2026-03-19 17:11:08','2026-03-19 17:11:08','Navigator Duffelpack','{"tone": "Exciting, polished, and professional", "caption_structure": "Short, punchy sentence to build excitement, followed by value proposition, and a clear call-to-action.", "cta_pattern": "Direct instructions to shop via link in bio.", "emoji_usage": "Minimal and strategic, using symbols to emphasize emotion and direction.", "post_format": "Product-focused carousel featuring hero lifestyle/studio hybrid imagery.", "hook_style": "Direct announcement hook to capture immediate interest.", "hashtag_strategy": "Minimalist, focused on brand identity and core product category.", "image_style": "Clean studio product photography with creative digital composite background.", "background_description": "Gradient light grey background featuring a rounded-rectangular window shape showing a clear blue sky and fluffy white clouds to evoke travel themes.", "color_palette": "Monochromatic neutrals (black and beige) contrasted with bright sky blue and white.", "people_and_models": "None, focus is entirely on the product.", "product_placement": "Hero placement with the two luggage pieces side-by-side in the center, clearly displaying branding.", "overall_vibe": "Sophisticated, aspirational, and clean, highlighting a premium travel experience."}');
